 790         PermittedRHS ? PoisonValue::get(PermittedRHS->getType()) : V, nullptr);
 791   }
 792 
 793   if (isa<ConstantAggregateZero>(V)) {
 794     Mask.assign(NumElts, 0);
 795     return std::make_pair(V, nullptr);
 796   }
