3114   // ShuffleVectorInst is equivalent to the original one.
3115   for (unsigned i = 0; i < VWidth; ++i) {
3116     int eltMask;
3117     if (Mask[i] < 0) {
3118       // This element is a poison value.
3119       eltMask = -1;
3120     } else if (Mask[i] < (int)LHSWidth) {
3121       // This element is from left hand side vector operand.
3122       //
3123       // If LHS is going to be replaced (case 1, 2, or 4), calculate the
3124       // new mask value for the element.
3125       if (newLHS != LHS) {
3126         eltMask = LHSMask[Mask[i]];
3127         // If the value selected is an poison value, explicitly specify it
3128         // with a -1 mask value.
3129         if (eltMask >= (int)LHSOp0Width && isa<PoisonValue>(LHSOp1))
3130           eltMask = -1;
3131       } else
3132         eltMask = Mask[i];
3133     } else {
3134       // This element is from right hand side vector operand
3135       //
3136       // If the value selected is a poison value, explicitly specify it
3137       // with a -1 mask value. (case 1)
3138       if (match(RHS, m_Poison()))
3139         eltMask = -1;
3140       // If RHS is going to be replaced (case 3 or 4), calculate the
3141       // new mask value for the element.
3142       else if (newRHS != RHS) {
3143         eltMask = RHSMask[Mask[i]-LHSWidth];
3144         // If the value selected is an poison value, explicitly specify it
3145         // with a -1 mask value.
3146         if (eltMask >= (int)RHSOp0Width) {
3147           assert(match(RHSShuffle->getOperand(1), m_Poison()) &&
3148                  "should have been check above");
3149           eltMask = -1;
3150         }
3151       } else
3152         eltMask = Mask[i]-LHSWidth;
3153 
3154       // If LHS's width is changed, shift the mask value accordingly.
3155       // If newRHS == nullptr, i.e. LHSOp0 == RHSOp0, we want to remap any
3156       // references from RHSOp0 to LHSOp0, so we don't need to shift the mask.
3157       // If newRHS == newLHS, we want to remap any references from newRHS to
3158       // newLHS so that we can properly identify splats that may occur due to
3159       // obfuscation across the two vectors.
3160       if (eltMask >= 0 && newRHS != nullptr && newLHS != newRHS)
