3171     newMask.push_back(eltMask);
3172   }
3173 
3174   // If the result mask is equal to one of the original shuffle masks,
3175   // or is a splat, do the replacement.
3176   if (isSplat || newMask == LHSMask || newMask == RHSMask || newMask == Mask) {
3177     if (!newRHS)
